import React from "react";
import { Link } from "react-router-dom";

export default function Navbar() {
  const styles = {
    navbar: {
      display: "flex",
      justifyContent: "space-between",
      alignItems: "center",
      padding: "14px 7%",
      background: "rgba(255, 255, 255, 0.97)",
      boxShadow: "0 3px 10px rgba(0, 0, 0, 0.1)",
      position: "sticky",
      top: 0,
      zIndex: 1000,
      fontFamily: "Poppins, sans-serif",
      backdropFilter: "blur(12px)",
    },
    logo: {
      textDecoration: "none",
      fontSize: "1.9rem",
      fontWeight: 700,
      color: "#ff385c",
      display: "flex",
      alignItems: "center",
      letterSpacing: "0.5px",
      transition: "transform 0.3s ease",
    },
    logoEmoji: {
      marginRight: "8px",
      fontSize: "1.9rem",
    },
    navLinks: {
      display: "flex",
      justifyContent: "center",
      alignItems: "center",
      gap: "50px", // Separate each link properly
    },
    navItem: {
      textDecoration: "none",
      color: "#333",
      fontSize: "1rem",
      fontWeight: 500,
      position: "relative",
      transition: "color 0.3s ease",
    },
    signupBtn: {
      backgroundColor: "#ff385c",
      color: "white",
      padding: "8px 22px",
      borderRadius: "25px",
      fontWeight: 600,
      textDecoration: "none",
      boxShadow: "0 4px 12px rgba(255, 56, 92, 0.25)",
      transition: "all 0.3s ease",
    },
  };

  return (
    <nav style={styles.navbar}>
      {/* 🏡 Logo */}
      <Link
        to="/"
        style={styles.logo}
        onMouseEnter={(e) => (e.target.style.transform = "scale(1.05)")}
        onMouseLeave={(e) => (e.target.style.transform = "scale(1)")}
      >
        <span style={styles.logoEmoji}>🏡</span> Airbnb
      </Link>

      {/* 🔗 Center Navigation Links */}
      <div style={styles.navLinks}>
        <Link
          to="/"
          style={styles.navItem}
          onMouseEnter={(e) => (e.target.style.color = "#ff385c")}
          onMouseLeave={(e) => (e.target.style.color = "#333")}
        >
          Home
        </Link>

        <Link
          to="/experience"
          style={styles.navItem}
          onMouseEnter={(e) => (e.target.style.color = "#ff385c")}
          onMouseLeave={(e) => (e.target.style.color = "#333")}
        >
          Experience
        </Link>

        <Link
          to="/services"
          style={styles.navItem}
          onMouseEnter={(e) => (e.target.style.color = "#ff385c")}
          onMouseLeave={(e) => (e.target.style.color = "#333")}
        >
          Services
        </Link>
      </div>

      {/* 🔘 Login & Signup */}
      <div style={{ display: "flex", gap: "20px", alignItems: "center" }}>
        <Link
          to="/login"
          style={styles.navItem}
          onMouseEnter={(e) => (e.target.style.color = "#ff385c")}
          onMouseLeave={(e) => (e.target.style.color = "#333")}
        >
          Login
        </Link>

        <Link
          to="/signup"
          style={styles.signupBtn}
          onMouseEnter={(e) => (e.target.style.backgroundColor = "#e31c5f")}
          onMouseLeave={(e) => (e.target.style.backgroundColor = "#ff385c")}
        >
          Sign Up
        </Link>
      </div>
    </nav>
  );
}
